function makeMockPrerender(): {
    app: Koa;
    router: Router;
    server: Server;
    stop: () => Promise<void>;
    setResponder: (responder: (ctxt: Koa.Context, body: any, type: 'card' | 'module' | 'command') => Promise<void> | void) => void;
} {
    let app = new Koa();
    let router = new Router();
    router.get('/', (ctxt) => {
        ctxt.status = 200;
        ctxt.body = 'OK';
    });
    let responder: (ctxt: Koa.Context, body: any, type: 'card' | 'module' | 'command') => Promise<void> | void = defaultResponder;
    async function readBody(ctxt: Koa.Context) {
        return await new Promise<string>((resolve) => {
            let buf: Buffer[] = [];
            ctxt.req.on('data', (c) => buf.push(c));
            ctxt.req.on('end', () => resolve(Buffer.concat(buf).toString('utf8')));
        });
    }
    function defaultResponder(ctxt: Koa.Context, body: any, type: 'card' | 'module' | 'command') {
        ctxt.status = 201;
        ctxt.set('Content-Type', 'application/vnd.api+json');
        if (type === 'card') {
            ctxt.body = JSON.stringify({
                data: {
                    type: 'prerender-result',
                    id: body?.data?.attributes?.url || 'x',
                    attributes: { ok: true },
                },
                meta: {
                    timing: { launchMs: 0, renderMs: 0, totalMs: 0 },
                    pool: {
                        pageId: 'p',
                        realm: body?.data?.attributes?.realm,
                        reused: false,
                        evicted: false,
                    },
                },
            });
        }
        else if (type === 'module') {
            ctxt.body = JSON.stringify({
                data: {
                    type: 'prerender-module-result',
                    id: body?.data?.attributes?.url || 'x',
                    attributes: {
                        id: body?.data?.attributes?.url || 'x',
                        status: 'ready',
                        isShimmed: false,
                        nonce: '1',
                        lastModified: 0,
                        createdAt: 0,
                        deps: [],
                        definitions: {},
                    },
                },
                meta: {
                    timing: { launchMs: 0, renderMs: 0, totalMs: 0 },
                    pool: {
                        pageId: 'p',
                        realm: body?.data?.attributes?.realm,
                        reused: false,
                        evicted: false,
                    },
                },
            });
        }
        else {
            ctxt.body = JSON.stringify({
                data: {
                    type: 'command-result',
                    id: body?.data?.attributes?.command || 'command',
                    attributes: {
                        status: 'ready',
                        cardResultString: null,
                    },
                },
                meta: {
                    timing: { launchMs: 0, renderMs: 0, totalMs: 0 },
                    pool: {
                        pageId: 'p',
                        realm: body?.data?.attributes?.realm,
                        reused: false,
                        evicted: false,
                    },
                },
            });
        }
    }
    router.post('/prerender-card', async (ctxt) => {
        let raw = await readBody(ctxt);
        let body = raw ? JSON.parse(raw) : {};
        await responder(ctxt, body, 'card');
    });
    router.post('/prerender-module', async (ctxt) => {
        let raw = await readBody(ctxt);
        let body = raw ? JSON.parse(raw) : {};
        await responder(ctxt, body, 'module');
    });
    router.post('/run-command', async (ctxt) => {
        let raw = await readBody(ctxt);
        let body = raw ? JSON.parse(raw) : {};
        await responder(ctxt, body, 'command');
    });
    app.use(router.routes());
    let server = createServer(app.callback()).listen(0);
    let stopped = false;
    return {
        app,
        router,
        server,
        stop: () => new Promise((resolve) => {
            if (stopped)
                return resolve();
            stopped = true;
            server.close(() => resolve());
        }),
        setResponder: (r) => {
            responder = r;
        },
    };
}
function makeBody(realm: string, url: string) {
    let auth = makeAuth(realm);
    return {
        data: {
            type: 'prerender-request',
            attributes: {
                url,
                auth,
                realm,
            },
        },
    };
}
function makeModuleBody(realm: string, url: string) {
    let auth = makeAuth(realm);
    return {
        data: {
            type: 'prerender-module-request',
            attributes: {
                url,
                auth,
                realm,
            },
        },
    };
}
function makeCommandBody(realm: string, command: string) {
    let auth = makeAuth(realm);
    return {
        data: {
            type: 'command-request',
            attributes: {
                realm,
                auth,
                command,
            },
        },
    };
}
function makeAuth(realm: string) {
    return testCreatePrerenderAuth('@user:localhost', {
        [realm]: ['read', 'write', 'realm-owner'],
    });
}
